1	const express = require('express');
2	const fs = require('fs');
3	const path = require('path');
4	const { exec } = require('child_process');
5	const util = require('util');
6	
7	const execAsync = util.promisify(exec);
8	
9	const app = express();
10	app.use(express.json());
11	app.use(express.static(path.join(__dirname, 'public')));
12	
13	const CLAUDE_DIR = path.join(process.env.HOME, '.claude');
14	const TEAMS_DIR = path.join(CLAUDE_DIR, 'teams');
15	const DESCRIPTIONS_FILE = path.join(__dirname, 'agents.json');
16	
17	// Load custom agent descriptions
18	function loadDescriptions() {
19	  try {
20	    const data = fs.readFileSync(DESCRIPTIONS_FILE, 'utf8');
21	    return JSON.parse(data);
22	  } catch {
23	    return {};
24	  }
25	}
26	
27	function saveDescriptions(descs) {
28	  fs.writeFileSync(DESCRIPTIONS_FILE, JSON.stringify(descs, null, 2));
29	}
30	
31	// Get all running agents from teams config files
32	function getRunningAgents() {
33	  const agents = [];
34	  const descriptions = loadDescriptions();
35	
36	  if (!fs.existsSync(TEAMS_DIR)) return agents;
37	
38	  const teamDirs = fs.readdirSync(TEAMS_DIR);
39	
40	  for (const teamName of teamDirs) {
41	    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');
42	    try {
43	      const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
44	
45	      if (config.members && config.members.length > 0) {
46	        for (const member of config.members) {
47	          const agentId = member.agentId;
48	          const descKey = agentId || teamName + '-' + member.name;
49	
50	          agents.push({
51	            id: agentId,
52	            name: member.name,
53	            teamName,
54	            type: member.agentType || 'general-purpose',
55	            description: descriptions[descKey] || '',
56	            sessionActive: member.sessionId ? true : false
57	          });
58	        }
59	      }
60	    } catch {
61	      // Skip invalid config files
62	    }
63	  }
64	
65	  return agents;
66	}
67	
68	// Get all team info
69	function getTeams() {
70	  const teams = [];
71	  if (!fs.existsSync(TEAMS_DIR)) return teams;
72	
73	  const teamDirs = fs.readdirSync(TEAMS_DIR);
74	
75	  for (const teamName of teamDirs) {
76	    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');
77	    try {
78	      const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
79	      const taskListPath = path.join(CLAUDE_DIR, 'tasks', teamName);
80	
81	      let taskStatus = { total: 0, completed: 0, inProgress: 0, pending: 0 };
82	      if (fs.existsSync(taskListPath)) {
83	        const taskFiles = fs.readdirSync(taskListPath).filter(f => f.endsWith('.json'));
84	        for (const taskFile of taskFiles) {
85	          try {
86	            const task = JSON.parse(fs.readFileSync(path.join(taskListPath, taskFile), 'utf8'));
87	            taskStatus.total++;
88	            if (task.status === 'completed') taskStatus.completed++;
89	            else if (task.status === 'in_progress') taskStatus.inProgress++;
90	            else if (task.status === 'pending') taskStatus.pending++;
91	          } catch {}
92	        }
93	      }
94	
95	      teams.push({
96	        name: teamName,
97	        description: config.description || '',
98	        memberCount: config.members?.length || 0,
99	        taskStatus
100	      });
101	    } catch {}
102	  }
103	
104	  return teams;
105	}
106	
107	// API: Get all running agents
108	app.get('/api/agents', (req, res) => {
109	  try {
110	    const agents = getRunningAgents();
111	    res.json({ success: true, agents });
112	  } catch (err) {
113	    res.status(500).json({ success: false, error: err.message });
114	  }
115	});
116	
117	// API: Get all teams
118	app.get('/api/teams', (req, res) => {
119	  try {
120	    const teams = getTeams();
121	    res.json({ success: true, teams });
122	  } catch (err) {
123	    res.status(500).json({ success: false, error: err.message });
124	  }
125	});
126	
127	// API: Save/update agent description
128	app.put('/api/agents/:id/description', (req, res) => {
129	  try {
130	    const descriptions = loadDescriptions();
131	    const id = req.params.id;
132	    descriptions[id] = req.body.description || '';
133	    saveDescriptions(descriptions);
134	    res.json({ success: true });
135	  } catch (err) {
136	    res.status(500).json({ success: false, error: err.message });
137	  }
138	});
139	
140	// API: Spawn agent - runs the claude command automatically
141	app.post('/api/spawn', async (req, res) => {
142	  try {
143	    const { name, role, prompt, description } = req.body;
144	    const fullPrompt = prompt || `${name} is a ${role} agent.`;
145	
146	    // Build the claude command
147	    // If spawning Trevor, use --agent=trevor to load the manager agent
148	    let cmd;
149	    if (name.toLowerCase() === 'trevor' || role === 'manager') {
150	      cmd = `claude --agent=trevor "${fullPrompt.replace(/"/g, '\\"')}"`;
151	    } else {
152	      cmd = `claude "${fullPrompt.replace(/"/g, '\\"')}"`;
153	    }
154	
155	    // Set up environment variables from settings.json
156	    let settingsEnv = {};
157	    try {
158	      const settingsPath = path.join(process.env.HOME, '.claude', 'settings.json');
159	      const settings = JSON.parse(fs.readFileSync(settingsPath, 'utf8'));
160	      settingsEnv = settings.env || {};
161	    } catch (e) {
162	      console.error('Could not read settings.json:', e.message);
163	    }
164	
165	    const teamTeams = settingsEnv.CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS || '1';
166	    const baseUrl = settingsEnv.ANTHROPIC_BASE_URL || '';
167	    const authToken = settingsEnv.ANTHROPIC_AUTH_TOKEN || '';
168	    const apiKey = settingsEnv.ANTHROPIC_API_KEY || '';
169	    const model = settingsEnv.ANTHROPIC_MODEL || '';
170	
171	    // Write a .command file with env vars set
172	    const scriptPath = path.join(__dirname, `spawn-${Date.now()}.command`);
173	    const scriptContent = `#!/bin/bash
174	export CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS=${teamTeams}
175	export ANTHROPIC_BASE_URL="${baseUrl}"
176	export ANTHROPIC_AUTH_TOKEN="${authToken}"
177	export ANTHROPIC_API_KEY="${apiKey}"
178	export ANTHROPIC_MODEL="${model}"
179	cd ~
180	${cmd}
181	echo ""
182	echo "Session ended. Press Enter to close."
183	read
184	`;
185	    fs.writeFileSync(scriptPath, scriptContent, { mode: 0o755 });
186	
187	    // Launch using 'open' — Terminal auto-runs .command files
188	    exec(`open "${scriptPath}"`, (err) => {
189	      if (err) console.error('Terminal open error:', err.message);
190	      else console.log(`Spawned agent: ${name}`);
191	      // Clean up script after 60s
192	      setTimeout(() => { try { fs.unlinkSync(scriptPath); } catch(e) {} }, 60000);
193	    });
194	
195	    // Save description
196	    if (description) {
197	      const descriptions = loadDescriptions();
198	      descriptions[name] = description;
199	      saveDescriptions(descriptions);
200	    }
201	
202	    // Create team entry so the dashboard can discover this agent
203	    const safeName = name.toLowerCase().replace(/[^a-z0-9]/g, '-');
204	    const teamName = `agent-${safeName}-${Date.now()}`;
205	    const teamDir = path.join(TEAMS_DIR, teamName);
206	    const taskListDir = path.join(CLAUDE_DIR, 'tasks', teamName);
207	
208	    fs.mkdirSync(teamDir, { recursive: true });
209	    fs.mkdirSync(taskListDir, { recursive: true });
210	
211	    const teamConfig = {
212	      description: description || `${name} — ${role} agent`,
213	      leaderSessionId: null,
214	      createdAt: Date.now(),
215	      members: [{
216	        agentId: `agent-${safeName}`,
217	        name,
218	        agentType: role || 'general-purpose'
219	      }]
220	    };
221	    fs.writeFileSync(
222	      path.join(teamDir, 'config.json'),
223	      JSON.stringify(teamConfig, null, 2)
224	    );
225	
226	    res.json({
227	      success: true,
228	      message: `Spawning "${name}" in a new Terminal window...`,
229	      name,
230	      teamName
231	    });
232	  } catch (err) {
233	    res.status(500).json({ success: false, error: err.message });
234	  }
235	});
236	
237	// API: Shutdown and clean up a team
238	app.delete('/api/teams/:name', (req, res) => {
239	  try {
240	    const teamName = req.params.name;
241	    const teamPath = path.join(TEAMS_DIR, teamName);
242	    const taskPath = path.join(CLAUDE_DIR, 'tasks', teamName);
243	
244	    if (fs.existsSync(teamPath)) {
245	      try {
246	        fs.rmSync(teamPath, { recursive: true, force: true });
247	      } catch (e) {
248	        // May be in use, just remove config
249	        const configFile = path.join(teamPath, 'config.json');
250	        if (fs.existsSync(configFile)) fs.unlinkSync(configFile);
251	      }
252	    }
253	    if (fs.existsSync(taskPath)) {
254	      fs.rmSync(taskPath, { recursive: true, force: true });
255	    }
256	
257	    res.json({ success: true, message: `Team "${teamName}" removed` });
258	  } catch (err) {
259	    res.status(500).json({ success: false, error: err.message });
260	  }
261	});
262	
263	const PORT = 3100;
264	app.listen(PORT, () => {
265	  console.log(`Agent Office Dashboard running on http://localhost:${PORT}`);
266	  console.log(`Teams directory: ${TEAMS_DIR}`);
267	});
268	
269	module.exports = app;
