9	// Canvas
10	const canvas = document.getElementById('officeCanvas');
11	const ctx = canvas.getContext('2d');
12	
13	// Tile size for pixel-art movement
14	const TILE = 48;
15	const COLS = 40;
16	const ROWS = 25;
17	let canvasW, canvasH;
18	
19	function resizeCanvas() {
20	  canvasW = canvas.parentElement.clientWidth;
21	  canvasH = Math.min(600, window.innerHeight - 250);
22	  canvas.width = canvasW;
23	  canvas.height = canvasH;
