400	// Draw player
401	function drawPlayer() {
402	  const screenX = player.x * TILE - camX;
403	  const screenY = player.y * TILE - camY;
404	
405	  // Bob animation
406	  const bob = Math.sin(player.pixelBob) * 2;
407	
408	  // Shadow
409	  ctx.fillStyle = 'rgba(0,0,0,0.2)';
410	  ctx.beginPath();
411	  ctx.ellipse(screenX + TILE / 2, screenY + TILE + 2, 12, 4, 0, 0, Math.PI * 2);
412	  ctx.fill();
413	
414	  // Body
415	  ctx.fillStyle = '#e53935';
416	  ctx.fillRect(screenX + 14, screenY + 12 + bob, 20, 22);
417	  // Head
418	  ctx.fillStyle = '#fdd8a5';
419	  ctx.fillRect(screenX + 16, screenY + 2 + bob, 16, 14);
420	  // Hat (red cap like a Pokemon trainer)
421	  ctx.fillStyle = '#e53935';
422	  ctx.fillRect(screenX + 14, screenY - 2 + bob, 20, 6);
423	  ctx.fillRect(screenX + 14, screenY + 2 + bob, 26, 3);
424	  // Eyes
425	  ctx.fillStyle = '#1a1a2e';
426	  const eyeOffX = player.dir === 'left' ? -2 : player.dir === 'right' ? 2 : 0;
427	  const eyeOffY = player.dir === 'up' ? -4 : player.dir === 'down' ? 2 : 0;
428	  if (player.dir !== 'up') {
429	    ctx.fillRect(screenX + 19 + eyeOffX, screenY + 8 + bob + eyeOffY, 3, 3);
430	    ctx.fillRect(screenX + 26 + eyeOffX, screenY + 8 + bob + eyeOffY, 3, 3);
431	  }
432	  // Legs
433	  ctx.fillStyle = '#1565c0';
434	  ctx.fillRect(screenX + 14, screenY + 32 + bob, 8, 12);
435	  ctx.fillRect(screenX + 26, screenY + 32 + bob, 8, 12);
436	  // Shoes
437	  ctx.fillStyle = '#fff';
438	  ctx.fillRect(screenX + 12, screenY + 42 + bob, 10, 4);
439	  ctx.fillRect(screenX + 24, screenY + 42 + bob, 10, 4);
440	}
