619	// Click handler for canvas - click on agents to inspect
620	canvas.addEventListener('click', (e) => {
621	  const rect = canvas.getBoundingClientRect();
622	  const clickX = e.clientX - rect.left + camX;
623	  const clickY = e.clientY - rect.top + camY;
624	
625	  const agentPositions = getAgentPositions();
626	  for (const pos of agentPositions) {
627	    // Find the tile for the agent
628	    const tileX = pos.x;
629	    const tileY = pos.y;
630	    if (clickX >= tileX * TILE && clickX < (tileX + 1) * TILE &&
631	        clickY >= tileY * TILE && clickY < (tileY + 1) * TILE) {
632	      openAgentDetail(pos.agent.id);
633	      return;
634	    }
635	  }
636	
637	  // Check if clicking near an agent's name tag
638	  for (const pos of agentPositions) {
639	    const agentX = pos.x * TILE;
640	    const agentY = pos.y * TILE - 8;
641	    if (clickX >= agentX && clickX < agentX + TILE &&
642	        clickY >= agentY && clickY < agentY + TILE) {
643	      openAgentDetail(pos.agent.id);
644	      return;
645	    }
646	  }
647	});
