68	// Get all team info
69	function getTeams() {
70	  const teams = [];
71	  if (!fs.existsSync(TEAMS_DIR)) return teams;
72	
73	  const teamDirs = fs.readdirSync(TEAMS_DIR);
74	
75	  for (const teamName of teamDirs) {
76	    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');
77	    try {
78	      const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
79	      const taskListPath = path.join(CLAUDE_DIR, 'tasks', teamName);
80	
81	      let taskStatus = { total: 0, completed: 0, inProgress: 0, pending: 0 };
82	      if (fs.existsSync(taskListPath)) {
83	        const taskFiles = fs.readdirSync(taskListPath).filter(f => f.endsWith('.json'));
84	        for (const taskFile of taskFiles) {
85	          try {
86	            const task = JSON.parse(fs.readFileSync(path.join(taskListPath, taskFile), 'utf8'));
87	            taskStatus.total++;
88	            if (task.status === 'completed') taskStatus.completed++;
89	            else if (task.status === 'in_progress') taskStatus.inProgress++;
90	            else if (task.status === 'pending') taskStatus.pending++;
91	          } catch {}
92	        }
93	      }
94	
95	      teams.push({
96	        name: teamName,
97	        description: config.description || '',
98	        memberCount: config.members?.length || 0,
99	        taskStatus
100	      });
101	    } catch {}
102	  }
103	
104	  return teams;
105	}
