const express = require('express');
const fs = require('fs');
const path = require('path');
const { exec, execSync } = require('child_process');
const util = require('util');

const execAsync = util.promisify(exec);

const app = express();
app.use(express.json());
app.use(express.static(path.join(__dirname, 'public')));

const CLAUDE_DIR = path.join(process.env.HOME, '.claude');
const TEAMS_DIR = path.join(CLAUDE_DIR, 'teams');
const DESCRIPTIONS_FILE = path.join(__dirname, 'agents.json');

// Load custom agent descriptions
function loadDescriptions() {
  try {
    const data = fs.readFileSync(DESCRIPTIONS_FILE, 'utf8');
    return JSON.parse(data);
  } catch {
    return {};
  }
}

function saveDescriptions(descs) {
  fs.writeFileSync(DESCRIPTIONS_FILE, JSON.stringify(descs, null, 2));
}

function checkTmuxSession(sessionName) {
  try {
    execSync(`tmux has-session -t ${sessionName} 2>/dev/null`, { encoding: 'utf8' });
    return true;
  } catch {
    return false;
  }
}

// Get all running agents from teams config files
function getRunningAgents() {
  const agents = [];
  const descriptions = loadDescriptions();

  if (!fs.existsSync(TEAMS_DIR)) return agents;

  const teamDirs = fs.readdirSync(TEAMS_DIR);

  for (const teamName of teamDirs) {
    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');
    try {
      const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));

      if (config.members && config.members.length > 0) {
        for (const member of config.members) {
          const agentId = member.agentId;
          const descKey = agentId || teamName + '-' + member.name;
          const tmuxSession = member.tmuxSession;
          const sessionAlive = tmuxSession ? checkTmuxSession(tmuxSession) : false;

          agents.push({
            id: agentId,
            name: member.name,
            teamName,
            type: member.agentType || 'general-purpose',
            description: descriptions[descKey] || '',
            sessionActive: sessionAlive,
            tmuxSession: tmuxSession || null
          });
        }
      }
    } catch {
      // Skip invalid config files
    }
  }

  return agents;
}

// Get all team info
function getTeams() {
  const teams = [];
  if (!fs.existsSync(TEAMS_DIR)) return teams;

  const teamDirs = fs.readdirSync(TEAMS_DIR);

  for (const teamName of teamDirs) {
    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');
    try {
      const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
      const taskListPath = path.join(CLAUDE_DIR, 'tasks', teamName);

      let taskStatus = { total: 0, completed: 0, inProgress: 0, pending: 0 };
      if (fs.existsSync(taskListPath)) {
        const taskFiles = fs.readdirSync(taskListPath).filter(f => f.endsWith('.json'));
        for (const taskFile of taskFiles) {
          try {
            const task = JSON.parse(fs.readFileSync(path.join(taskListPath, taskFile), 'utf8'));
            taskStatus.total++;
            if (task.status === 'completed') taskStatus.completed++;
            else if (task.status === 'in_progress') taskStatus.inProgress++;
            else if (task.status === 'pending') taskStatus.pending++;
          } catch {}
        }
      }

      teams.push({
        name: teamName,
        description: config.description || '',
        memberCount: config.members?.length || 0,
        taskStatus
      });
    } catch {}
  }

  return teams;
}

// API: Get all running agents
app.get('/api/agents', (req, res) => {
  try {
    const agents = getRunningAgents();
    res.json({ success: true, agents });
  } catch (err) {
    res.status(500).json({ success: false, error: err.message });
  }
});

// API: Wake up a team by re-spawning the agent in tmux
app.post('/api/wake/:name', (req, res) => {
  try {
    const teamName = req.params.name;
    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');

    if (!fs.existsSync(teamConfigPath)) {
      return res.status(404).json({ success: false, error: 'Team not found' });
    }

    const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
    if (!config.members || config.members.length === 0) {
      return res.status(400).json({ success: false, error: 'Team has no members' });
    }

    // Read env vars from settings.json
    let settingsEnv = {};
    try {
      const settingsPath = path.join(process.env.HOME, '.claude', 'settings.json');
      const settings = JSON.parse(fs.readFileSync(settingsPath, 'utf8'));
      settingsEnv = settings.env || {};
    } catch (e) {
      console.error('Could not read settings.json:', e.message);
    }

    const teamTeams = settingsEnv.CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS || '1';
    const baseUrl = settingsEnv.ANTHROPIC_BASE_URL || '';
    const authToken = settingsEnv.ANTHROPIC_AUTH_TOKEN || '';
    const apiKey = settingsEnv.ANTHROPIC_API_KEY || '';
    const model = settingsEnv.ANTHROPIC_MODEL || '';

    let results = [];

    for (const member of config.members) {
      const oldSession = member.tmuxSession;
      const newSession = config.description?.replace(/[^\w-]/g, '-').toLowerCase() || teamName;
      const tmuxSession = oldSession ? `${newSession}-${Date.now()}` : undefined;

      // Check if old session is still alive
      if (oldSession) {
        const wasAlive = checkTmuxSession(oldSession);
        if (!wasAlive) {
          // Kill dead session and create new one
          try { execSync(`tmux kill-session -t ${oldSession} 2>/dev/null`); } catch {}
        }
      }

      if (tmuxSession) {
        const { name, agentType } = member;
        let cmd;
        if (name.toLowerCase() === 'trevor' || agentType === 'manager' || agentType === 'trevor') {
          cmd = 'claude --agent=trevor ""';
        } else {
          cmd = `claude "Wake up agent ${name}, continue previous work."`;
        }

        const scriptPath = path.join(__dirname, `wake-${tmuxSession}.command`);
        const scriptContent = `#!/bin/bash
export CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS=${teamTeams}
export ANTHROPIC_BASE_URL="${baseUrl}"
export ANTHROPIC_AUTH_TOKEN="${authToken}"
export ANTHROPIC_API_KEY="${apiKey}"
export ANTHROPIC_MODEL="${model}"
cd ~
${cmd}
`;
        fs.writeFileSync(scriptPath, scriptContent, { mode: 0o755 });

        execSync(`tmux new-session -d -s "${tmuxSession}" bash "${scriptPath}"`);

        // Update config with new tmux session
        member.tmuxSession = tmuxSession;

        results.push({ name, session: tmuxSession, status: 'restarted' });

        // Clean up script after 60s
        setTimeout(() => { try { fs.unlinkSync(scriptPath); } catch(e) {} }, 60000);
      } else {
        results.push({ name, status: 'no_session_to_resume' });
      }
    }

    // Save updated config
    fs.writeFileSync(teamConfigPath, JSON.stringify(config, null, 2));

    res.json({ success: true, message: `Woke up team "${teamName}"`, agents: results });
  } catch (err) {
    res.status(500).json({ success: false, error: err.message });
  }
});

// API: Get all teams with session info
app.get('/api/teams', (req, res) => {
  try {
    const teams = getTeams();
    res.json({ success: true, teams });
  } catch (err) {
    res.status(500).json({ success: false, error: err.message });
  }
});

// API: Save/update agent description
app.put('/api/agents/:id/description', (req, res) => {
  try {
    const descriptions = loadDescriptions();
    const id = req.params.id;
    descriptions[id] = req.body.description || '';
    saveDescriptions(descriptions);
    res.json({ success: true });
  } catch (err) {
    res.status(500).json({ success: false, error: err.message });
  }
});

// Check if a tmux session exists
// API: Spawn agent - runs the claude command in a detached tmux session
app.post('/api/spawn', async (req, res) => {
  try {
    const { name, role, prompt, description } = req.body;
    const fullPrompt = prompt || `${name} is a ${role} agent.`;

    // Build the claude command
    let cmd;
    if (name.toLowerCase() === 'trevor' || role === 'manager' || role === 'trevor') {
      cmd = `claude --agent=trevor "${fullPrompt.replace(/"/g, '\\"')}"`;
    } else {
      cmd = `claude "${fullPrompt.replace(/"/g, '\\"')}"`;
    }

    // Set up environment variables from settings.json
    let settingsEnv = {};
    try {
      const settingsPath = path.join(process.env.HOME, '.claude', 'settings.json');
      const settings = JSON.parse(fs.readFileSync(settingsPath, 'utf8'));
      settingsEnv = settings.env || {};
    } catch (e) {
      console.error('Could not read settings.json:', e.message);
    }

    const teamTeams = settingsEnv.CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS || '1';
    const baseUrl = settingsEnv.ANTHROPIC_BASE_URL || '';
    const authToken = settingsEnv.ANTHROPIC_AUTH_TOKEN || '';
    const apiKey = settingsEnv.ANTHROPIC_API_KEY || '';
    const model = settingsEnv.ANTHROPIC_MODEL || '';

    const safeName = name.toLowerCase().replace(/[^a-z0-9]/g, '-');
    const teamName = `agent-${safeName}-${Date.now()}`;
    const tmuxSession = `${safeName}-${Date.now()}`;

    // Write a .command file with env vars set
    const scriptPath = path.join(__dirname, `spawn-${Date.now()}.command`);
    const scriptContent = `#!/bin/bash
export CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS=${teamTeams}
export ANTHROPIC_BASE_URL="${baseUrl}"
export ANTHROPIC_AUTH_TOKEN="${authToken}"
export ANTHROPIC_API_KEY="${apiKey}"
export ANTHROPIC_MODEL="${model}"
cd ~
${cmd}
`;
    fs.writeFileSync(scriptPath, scriptContent, { mode: 0o755 });

    // Launch in detached tmux session - runs in background without visible window
    exec(`tmux new-session -d -s "${tmuxSession}" bash "${scriptPath}"`, (err) => {
      if (err) console.error('tmux spawn error:', err.message);
      else console.log(`Spawned agent in tmux: ${tmuxSession}`);
      // Clean up script after 60s
      setTimeout(() => { try { fs.unlinkSync(scriptPath); } catch(e) {} }, 60000);
    });

    // Save description
    if (description) {
      const descriptions = loadDescriptions();
      descriptions[name] = description;
      saveDescriptions(descriptions);
    }

    // Create team entry so the dashboard can discover this agent
    const teamDir = path.join(TEAMS_DIR, teamName);
    const taskListDir = path.join(CLAUDE_DIR, 'tasks', teamName);

    fs.mkdirSync(teamDir, { recursive: true });
    fs.mkdirSync(taskListDir, { recursive: true });

    const teamConfig = {
      description: description || `${name} — ${role} agent`,
      leaderSessionId: null,
      createdAt: Date.now(),
      tmuxSession,
      members: [{
        agentId: `agent-${safeName}`,
        name,
        agentType: role || 'general-purpose',
        tmuxSession
      }]
    };
    fs.writeFileSync(
      path.join(teamDir, 'config.json'),
      JSON.stringify(teamConfig, null, 2)
    );

    res.json({
      success: true,
      message: `Agent "${name}" spawned in background (tmux session: ${tmuxSession})`,
      name,
      teamName,
      tmuxSession
    });
  } catch (err) {
    res.status(500).json({ success: false, error: err.message });
  }
});

// API: Shutdown and clean up a team
app.delete('/api/teams/:name', (req, res) => {
  try {
    const teamName = req.params.name;
    const teamPath = path.join(TEAMS_DIR, teamName);
    const taskPath = path.join(CLAUDE_DIR, 'tasks', teamName);

    if (fs.existsSync(teamPath)) {
      try {
        fs.rmSync(teamPath, { recursive: true, force: true });
      } catch (e) {
        // May be in use, just remove config
        const configFile = path.join(teamPath, 'config.json');
        if (fs.existsSync(configFile)) fs.unlinkSync(configFile);
      }
    }
    if (fs.existsSync(taskPath)) {
      fs.rmSync(taskPath, { recursive: true, force: true });
    }

    res.json({ success: true, message: `Team "${teamName}" removed` });
  } catch (err) {
    res.status(500).json({ success: false, error: err.message });
  }
});

const PORT = 3100;
app.listen(PORT, () => {
  console.log(`Agent Office Dashboard running on http://localhost:${PORT}`);
  console.log(`Teams directory: ${TEAMS_DIR}`);
});

module.exports = app;

