          const descKey = agentId || teamName + '-' + member.name;
          const tmuxSession = member.tmuxSession;
          const backgroundId = member.backgroundId || teamName;

          // Check tmux if available
          let sessionAlive = false;
          if (tmuxSession) {
            sessionAlive = checkTmuxSession(tmuxSession);
          } else if (backgroundId) {
            const pid = loadPid(`${backgroundId}.pid`);
            sessionAlive = checkPidAlive(pid);
          }

          agents.push({
            id: agentId,
            name: member.name,
            teamName,
            type: member.agentType || 'general-purpose',
            description: descriptions[descKey] || '',
            sessionActive: sessionAlive,
            tmuxSession: tmuxSession || null
          });
        }
      }
    } catch {
      // Skip invalid config files
    }
  }

  return agents;
}

