      let cmd;
      if (name.toLowerCase() === 'trevor' || agentType === 'manager' || agentType === 'trevor') {
        cmd = '--agent=trevor -p "Resume your previous work as manager agent."';
      } else {
        cmd = `-p "Wake up agent ${name}, continue previous work."`;
      }

